23	#include "mupdf/fitz.h"
24	
25	#include <limits.h>
26	#include <string.h>
27	#include <stdlib.h>
28	#include <stdio.h>
29	#include <errno.h>
30	
31	/* Enable FITZ_DEBUG_LOCKING_TIMES below if you want to check the times
32	 * for which locks are held too. */
33	#ifdef FITZ_DEBUG_LOCKING
34	#undef FITZ_DEBUG_LOCKING_TIMES
35	#endif
36	
37	/*
38	 * The malloc family of functions will always try scavenging when they run out of memory.
39	 * They will only fail when scavenging cannot free up memory from caches in the fz_context.
40	 * All the functions will throw an exception when no memory can be allocated,
41	 * except the _no_throw family which instead silently returns NULL.
42	 */
43	
44	static void *
45	do_scavenging_malloc(fz_context *ctx, size_t size)
46	{
47		void *p;
48		int phase = 0;
49	
50		fz_lock(ctx, FZ_LOCK_ALLOC);
51		do {
52			p = ctx->alloc.malloc(ctx->alloc.user, size);
53			if (p != NULL)
54			{
55				fz_unlock(ctx, FZ_LOCK_ALLOC);
56				return p;
57			}
58		}
59	#ifdef MEMENTO_SQUEEZEBUILD
60		while (0);
61		(void) phase;
62	#else
63		while (fz_store_scavenge(ctx, size, &phase));
64	#endif
65		fz_unlock(ctx, FZ_LOCK_ALLOC);
66	
67		return NULL;
68	}
69	
70	static void *
71	do_scavenging_realloc(fz_context *ctx, void *p, size_t size)
72	{
73		void *q;
74		int phase = 0;
75	
76		fz_lock(ctx, FZ_LOCK_ALLOC);
77		do {
78			q = ctx->alloc.realloc(ctx->alloc.user, p, size);
79			if (q != NULL)
80			{
81				fz_unlock(ctx, FZ_LOCK_ALLOC);
82				return q;
83			}
84		}
85	#ifdef MEMENTO_SQUEEZEBUILD
86		while (0);
87		(void) phase;
88	#else
89		while (fz_store_scavenge(ctx, size, &phase));
90	#endif
91		fz_unlock(ctx, FZ_LOCK_ALLOC);
92	
93		return NULL;
94	}
95	
96	void *
97	fz_malloc(fz_context *ctx, size_t size)
98	{
99		void *p;
100		if (size == 0)
101			return NULL;
102		p = do_scavenging_malloc(ctx, size);
103		if (!p)
104		{
105			errno = ENOMEM;
106			fz_throw(ctx, FZ_ERROR_SYSTEM, "malloc (%zu bytes) failed", size);
107		}
108		return p;
109	}
110	
111	void *
112	fz_malloc_no_throw(fz_context *ctx, size_t size)
113	{
114		if (size == 0)
115			return NULL;
116		return do_scavenging_malloc(ctx, size);
117	}
118	
119	void *
120	fz_malloc_array_imp(fz_context *ctx, size_t nmemb, size_t size)
121	{
122		size_t total;
123		if (fz_ckd_mul_size(&total, nmemb, size))
124			fz_throw(ctx, FZ_ERROR_SYSTEM, "malloc array (%zu x %zu bytes) failed (overflow)", nmemb, size);
125		return fz_malloc(ctx, total);
126	}
127	
128	void *
129	fz_realloc_array_imp(fz_context *ctx, void *p, size_t nmemb, size_t size)
130	{
131		size_t total;
132		if (fz_ckd_mul_size(&total, nmemb, size))
133			fz_throw(ctx, FZ_ERROR_SYSTEM, "realloc array (%zu x %zu bytes) failed (overflow)", nmemb, size);
134		return fz_realloc(ctx, p, total);
135	}
136	
137	void *
138	fz_calloc(fz_context *ctx, size_t count, size_t size)
139	{
140		void *p;
141		size_t total;
142		if (count == 0 || size == 0)
143			return NULL;
144		if (fz_ckd_mul_size(&total, count, size))
145			fz_throw(ctx, FZ_ERROR_SYSTEM, "calloc (%zu x %zu bytes) failed (overflow)", count, size);
146		p = do_scavenging_malloc(ctx, total);
147		if (!p)
148		{
149			errno = ENOMEM;
150			fz_throw(ctx, FZ_ERROR_SYSTEM, "calloc (%zu x %zu bytes) failed", count, size);
151		}
152		memset(p, 0, count*size);
153		return p;
154	}
155	
156	void *
157	fz_calloc_no_throw(fz_context *ctx, size_t count, size_t size)
158	{
159		void *p;
160		size_t total;
161		if (count == 0 || size == 0)
162			return NULL;
163		if (fz_ckd_mul_size(&total, count, size))
164			return NULL;
165		p = do_scavenging_malloc(ctx, total);
166		if (p)
167			memset(p, 0, total);
168		return p;
169	}
170	
171	void *
172	fz_realloc(fz_context *ctx, void *p, size_t size)
173	{
174		if (size == 0)
175		{
176			fz_free(ctx, p);
177			return NULL;
178		}
179		p = do_scavenging_realloc(ctx, p, size);
180		if (!p)
181		{
182			errno = ENOMEM;
183			fz_throw(ctx, FZ_ERROR_SYSTEM, "realloc (%zu bytes) failed", size);
184		}
185		return p;
186	}
187	
188	void *
189	fz_realloc_no_throw(fz_context *ctx, void *p, size_t size)
190	{
191		if (size == 0)
192		{
193			fz_free(ctx, p);
194			return NULL;
195		}
196		return do_scavenging_realloc(ctx, p, size);
197	}
198	
199	void
200	fz_free(fz_context *ctx, void *p)
201	{
202		if (p)
203		{
204			fz_lock(ctx, FZ_LOCK_ALLOC);
205			ctx->alloc.free(ctx->alloc.user, p);
206			fz_unlock(ctx, FZ_LOCK_ALLOC);
207		}
208	}
209	
210	/* align is assumed to be a power of 2. */
211	void *fz_malloc_aligned(fz_context *ctx, size_t size, int align)
212	{
213		uint8_t *block;
214		uint8_t *aligned;
215	
216		if (size == 0)
217			return NULL;
218	
219		if (align >= 256)
220			fz_throw(ctx, FZ_ERROR_ARGUMENT, "Alignment too large");
221		if ((align & (align-1)) != 0)
222			fz_throw(ctx, FZ_ERROR_ARGUMENT, "Alignment must be a power of 2");
223	
224		block = fz_malloc(ctx, size + align);
225	
226		aligned = (void *)((intptr_t)(block + align-1) & ~(align-1));
227		if (aligned == block)
228			aligned = block + align;
229		memset(block, aligned-block, aligned-block);
230	
231		return aligned;
232	}
233	
234	void fz_free_aligned(fz_context *ctx, void *ptr)
235	{
236		uint8_t *block = ptr;
237	
238		if (ptr == NULL)
239			return;
240	
241		block -= block[-1];
242	
243		fz_free(ctx, block);
244	}
245	
246	char *
247	fz_strdup(fz_context *ctx, const char *s)
248	{
249		size_t len = strlen(s) + 1;
250		char *ns = fz_malloc(ctx, len);
251		memcpy(ns, s, len);
252		return ns;
253	}
254	
255	fz_string *
256	fz_new_string(fz_context *ctx, const char *s)
257	{
258		fz_string *str = fz_malloc_flexible(ctx, fz_string, str, strlen(s) + 1);
259		str->refs = 1;
260		strcpy(str->str, s);
261		return str;
262	}
263	
264	fz_string *fz_keep_string(fz_context *ctx, fz_string *str)
265	{
266		return fz_keep_imp(ctx, str, &str->refs);
267	}
268	
269	void fz_drop_string(fz_context *ctx, fz_string *str)
270	{
271		if (fz_drop_imp(ctx, str, &str->refs))
272			fz_free(ctx, str);
273	}
274	
275	
276	static void *
277	fz_malloc_default(void *opaque, size_t size)
278	{
279		return malloc(size);
280	}
281	
282	static void *
283	fz_realloc_default(void *opaque, void *old, size_t size)
284	{
285		return realloc(old, size);
286	}
287	
288	static void
289	fz_free_default(void *opaque, void *ptr)
290	{
291		free(ptr);
292	}
293	
294	fz_alloc_context fz_alloc_default =
295	{
296		NULL,
297		fz_malloc_default,
298		fz_realloc_default,
299		fz_free_default
300	};
301	
302	static void
303	fz_lock_default(void *user, int lock)
304	{
305	}
306	
307	static void
308	fz_unlock_default(void *user, int lock)
309	{
310	}
311	
312	fz_locks_context fz_locks_default =
313	{
314		NULL,
315		fz_lock_default,
316		fz_unlock_default
317	};
318	
319	#ifdef FITZ_DEBUG_LOCKING
320	
321	enum
322	{
323		FZ_LOCK_DEBUG_CONTEXT_MAX = 100
324	};
325	
326	fz_context *fz_lock_debug_contexts[FZ_LOCK_DEBUG_CONTEXT_MAX];
327	int fz_locks_debug[FZ_LOCK_DEBUG_CONTEXT_MAX][FZ_LOCK_MAX];
328	
329	#ifdef FITZ_DEBUG_LOCKING_TIMES
330	
331	int fz_debug_locking_inited = 0;
332	int fz_lock_program_start;
333	int fz_lock_time[FZ_LOCK_DEBUG_CONTEXT_MAX][FZ_LOCK_MAX] = { { 0 } };
334	int fz_lock_taken[FZ_LOCK_DEBUG_CONTEXT_MAX][FZ_LOCK_MAX] = { { 0 } };
335	
336	/* We implement our own millisecond clock, as clock() cannot be trusted
337	 * when threads are involved. */
338	static int ms_clock(void)
339	{
340	#ifdef _WIN32
341		return (int)GetTickCount();
342	#else
343		struct timeval tp;
344		gettimeofday(&tp, NULL);
345		return (tp.tv_sec*1000) + (tp.tv_usec/1000);
346	#endif
347	}
348	
349	static void dump_lock_times(void)
350	{
351		int i, j;
352		int prog_time = ms_clock() - fz_lock_program_start;
353	
354		for (j = 0; j < FZ_LOCK_MAX; j++)
355		{
356			int total = 0;
357			for (i = 0; i < FZ_LOCK_DEBUG_CONTEXT_MAX; i++)
358			{
359				total += fz_lock_time[i][j];
360			}
361			printf("Lock %d held for %g seconds (%g%%)\n", j, total / 1000.0f, 100.0f*total/prog_time);
362		}
363		printf("Total program time %g seconds\n", prog_time / 1000.0f);
364	}
365	
366	#endif
367	
368	static int find_context(fz_context *ctx)
369	{
370		int i;
371	
372		for (i = 0; i < FZ_LOCK_DEBUG_CONTEXT_MAX; i++)
373		{
374			if (fz_lock_debug_contexts[i] == ctx)
375				return i;
376			if (fz_lock_debug_contexts[i] == NULL)
377			{
378				int gottit = 0;
379				/* We've not locked on this context before, so use
380				 * this one for this new context. We might have other
381				 * threads trying here too though so, so claim it
382				 * atomically. No one has locked on this context
383				 * before, so we are safe to take the ALLOC lock. */
384				ctx->locks.lock(ctx->locks.user, FZ_LOCK_ALLOC);
385				/* If it's still free, then claim it as ours,
386				 * otherwise we'll keep hunting. */
387				if (fz_lock_debug_contexts[i] == NULL)
388				{
389					gottit = 1;
390					fz_lock_debug_contexts[i] = ctx;
391	#ifdef FITZ_DEBUG_LOCKING_TIMES
392					if (fz_debug_locking_inited == 0)
393					{
394						fz_debug_locking_inited = 1;
395						fz_lock_program_start = ms_clock();
396						atexit(dump_lock_times);
397					}
398	#endif
399				}
400				ctx->locks.unlock(ctx->locks.user, FZ_LOCK_ALLOC);
401				if (gottit)
402					return i;
403			}
404		}
405		return -1;
406	}
407	
408	void
409	fz_assert_lock_held(fz_context *ctx, int lock)
410	{
411		int idx;
412	
413		if (ctx->locks.lock != fz_lock_default)
414			return;
415	
416		idx = find_context(ctx);
417		if (idx < 0)
418			return;
419	
420		if (fz_locks_debug[idx][lock] == 0)
421			fprintf(stderr, "Lock %d not held when expected\n", lock);
422	}
423	
424	void
425	fz_assert_lock_not_held(fz_context *ctx, int lock)
426	{
427		int idx;
428	
429		if (ctx->locks.lock != fz_lock_default)
430			return;
431	
432		idx = find_context(ctx);
433		if (idx < 0)
434			return;
435	
436		if (fz_locks_debug[idx][lock] != 0)
437			fprintf(stderr, "Lock %d held when not expected\n", lock);
438	}
439	
440	void fz_lock_debug_lock(fz_context *ctx, int lock)
441	{
442		int i, idx;
443	
444		if (ctx->locks.lock != fz_lock_default)
445			return;
446	
447		idx = find_context(ctx);
448		if (idx < 0)
449			return;
450	
451		if (fz_locks_debug[idx][lock] != 0)
452		{
453			fprintf(stderr, "Attempt to take lock %d when held already!\n", lock);
454		}
455		for (i = lock-1; i >= 0; i--)
456		{
457			if (fz_locks_debug[idx][i] != 0)
458			{
459				fprintf(stderr, "Lock ordering violation: Attempt to take lock %d when %d held already!\n", lock, i);
460			}
461		}
462		fz_locks_debug[idx][lock] = 1;
463	#ifdef FITZ_DEBUG_LOCKING_TIMES
464		fz_lock_taken[idx][lock] = ms_clock();
465	#endif
466	}
467	
468	void fz_lock_debug_unlock(fz_context *ctx, int lock)
469	{
470		int idx;
471	
472		if (ctx->locks.lock != fz_lock_default)
473			return;
474	
475		idx = find_context(ctx);
476		if (idx < 0)
477			return;
478	
479		if (fz_locks_debug[idx][lock] == 0)
480		{
481			fprintf(stderr, "Attempt to release lock %d when not held!\n", lock);
482		}
483		fz_locks_debug[idx][lock] = 0;
484	#ifdef FITZ_DEBUG_LOCKING_TIMES
485		fz_lock_time[idx][lock] += ms_clock() - fz_lock_taken[idx][lock];
486	#endif
487	}
488	
489	#else
490	
491	void
492	(fz_assert_lock_held)(fz_context *ctx, int lock)
493	{
494	}
495	
496	void
497	(fz_assert_lock_not_held)(fz_context *ctx, int lock)
498	{
499	}
500	
501	void (fz_lock_debug_lock)(fz_context *ctx, int lock)
502	{
503	}
504	
505	void (fz_lock_debug_unlock)(fz_context *ctx, int lock)
506	{
507	}
508	
509	#endif
510

