#if defined(__SANITIZE_ADDRESS__) || defined(__SANITIZE_UNDEFINED__)
#undef FZ_POINTER_ALIGN_MOD
#define FZ_POINTER_ALIGN_MOD FZ_MEMORY_BLOCK_ALIGN_MOD
